import React, { useState, useEffect } from 'react';
import axios from 'axios';

const CloudPhishingDB = () => {
    const [stats, setStats] = useState(null);
    const [checkResult, setCheckResult] = useState(null);
    const [loading, setLoading] = useState(false);
    const [url, setUrl] = useState('');

    const loadStats = async () => {
        try {
            const response = await axios.get('http://localhost:5001/cloud_db/stats');
            setStats(response.data);
        } catch (error) {
            console.error('Load stats error:', error);
        }
    };

    const checkUrl = async () => {
        if (!url) return;

        try {
            setLoading(true);
            const response = await axios.post('http://localhost:5001/cloud_db/check', {
                url
            });
            setCheckResult(response.data);
        } catch (error) {
            console.error('Check URL error:', error);
        } finally {
            setLoading(false);
        }
    };

    const addToDatabase = async () => {
        if (!url) return;

        try {
            setLoading(true);
            const response = await axios.post('http://localhost:5001/cloud_db/add', {
                url,
                threat_type: 'phishing',
                confidence: 0.9
            });
            alert(response.data.success ? 'Added successfully' : 'Failed to add');
            loadStats();
        } catch (error) {
            console.error('Add to DB error:', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadStats();
    }, []);

    return (
        <div className="cloud-db-container">
            <h3>Cloud Phishing Database</h3>

            {stats && (
                <div className="db-stats">
                    <h4>Database Statistics</h4>
                    <div className="stats-grid">
                        <div className="stat-card">
                            <div className="stat-value">{stats.total_urls}</div>
                            <div className="stat-label">Total URLs</div>
                        </div>
                        <div className="stat-card">
                            <div className="stat-value">{stats.active_urls}</div>
                            <div className="stat-label">Active URLs</div>
                        </div>
                        <div className="stat-card">
                            <div className="stat-value">{stats.recent_additions}</div>
                            <div className="stat-label">Added (7 days)</div>
                        </div>
                        <div className="stat-card">
                            <div className="stat-value">{stats.cache_size}</div>
                            <div className="stat-label">Cache Size</div>
                        </div>
                    </div>

                    {stats.sources && (
                        <div className="sources-list">
                            <h5>Sources</h5>
                            {stats.sources.map((source, index) => (
                                <div key={index} className="source-item">
                                    <span className="source-name">{source.source}</span>
                                    <span className="source-count">{source.count}</span>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            )}

            <div className="db-controls">
                <h4>Check URL</h4>
                <div className="input-group">
                    <input
                        type="text"
                        placeholder="Enter URL to check"
                        value={url}
                        onChange={(e) => setUrl(e.target.value)}
                    />
                    <button onClick={checkUrl} disabled={loading || !url}>
                        {loading ? 'Checking...' : 'Check'}
                    </button>
                    <button onClick={addToDatabase} disabled={loading || !url}>
                        Add to Database
                    </button>
                </div>
            </div>

            {checkResult && (
                <div className="check-result">
                    <h4>Check Result</h4>
                    <div className={`result-status ${checkResult.found ? 'found' : 'not-found'}`}>
                        {checkResult.found ? '⚠️ URL Found in Database' : '✅ URL Not Found'}
                    </div>

                    {checkResult.found && (
                        <div className="result-details">
                            {checkResult.match_type && (
                                <div>Match Type: {checkResult.match_type}</div>
                            )}
                            {checkResult.confidence && (
                                <div>Confidence: {(checkResult.confidence * 100).toFixed(1)}%</div>
                            )}
                            {checkResult.source && (
                                <div>Source: {checkResult.source}</div>
                            )}
                            {checkResult.patterns && (
                                <div className="patterns">
                                    <h5>Matched Patterns:</h5>
                                    {checkResult.patterns.map((pattern, index) => (
                                        <div key={index} className="pattern">
                                            <span className={`severity ${pattern.severity}`}>
                                                {pattern.severity}
                                            </span>
                                            <span>{pattern.pattern}</span>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    )}
                </div>
            )}

            <style jsx>{`
                .cloud-db-container {
                    padding: 20px;
                    background: #f5f5f5;
                    border-radius: 8px;
                }
                .db-stats {
                    margin-bottom: 30px;
                }
                .stats-grid {
                    display: grid;
                    grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
                    gap: 15px;
                    margin: 15px 0;
                }
                .stat-card {
                    padding: 15px;
                    background: white;
                    border-radius: 4px;
                    text-align: center;
                }
                .stat-value {
                    font-size: 2em;
                    font-weight: bold;
                    color: #007bff;
                }
                .stat-label {
                    color: #666;
                    font-size: 0.9em;
                }
                .sources-list {
                    margin-top: 15px;
                }
                .source-item {
                    display: flex;
                    justify-content: space-between;
                    padding: 8px;
                    background: white;
                    margin-bottom: 5px;
                    border-radius: 4px;
                }
                .source-count {
                    font-weight: bold;
                    color: #007bff;
                }
                .db-controls {
                    margin-bottom: 20px;
                }
                .input-group {
                    display: flex;
                    gap: 10px;
                    margin-top: 10px;
                }
                .input-group input {
                    flex: 1;
                    padding: 8px;
                    border: 1px solid #ddd;
                    border-radius: 4px;
                }
                .input-group button {
                    padding: 8px 16px;
                    background: #007bff;
                    color: white;
                    border: none;
                    border-radius: 4px;
                    cursor: pointer;
                }
                .input-group button:disabled {
                    background: #ccc;
                }
                .check-result {
                    padding: 15px;
                    background: white;
                    border-radius: 4px;
                }
                .result-status {
                    font-size: 1.2em;
                    margin: 10px 0;
                }
                .result-status.found {
                    color: #dc3545;
                }
                .result-status.not-found {
                    color: #28a745;
                }
                .result-details {
                    margin-top: 15px;
                }
                .patterns {
                    margin-top: 10px;
                }
                .pattern {
                    display: flex;
                    gap: 10px;
                    padding: 5px;
                    background: #f8f9fa;
                    margin-bottom: 5px;
                    border-radius: 4px;
                }
                .severity {
                    padding: 2px 6px;
                    border-radius: 3px;
                    font-size: 0.8em;
                    color: white;
                }
                .severity.LOW { background: #28a745; }
                .severity.MEDIUM { background: #ffc107; }
                .severity.HIGH { background: #dc3545; }
                .severity.CRITICAL { background: #721c24; }
            `}</style>
        </div>
    );
};

export default CloudPhishingDB;
